### [ASSUMPTION] Authentication Security Handwaving
**Accepted** - Security model is inadequate for long-lived connections.

**Revision**: Implement proper WebSocket authentication with token refresh:
```javascript
io.use(async (socket, next) => {
    try {
        const token = socket.handshake.auth.token;
        const decoded = jwt.verify(token, process.env.JWT_SECRET);

        // Store token expiration for refresh tracking
        socket.user = decoded;
        socket.tokenExpiry = decoded.exp * 1000;

        // Schedule token refresh check
        this.scheduleTokenRefresh(socket);

        next();
    } catch (err) {
        next(new Error('Authentication error'));
    }
});

scheduleTokenRefresh(socket) {
    const timeToExpiry = socket.tokenExpiry - Date.now();
    const refreshTime = timeToExpiry - (5 * 60 * 1000); // 5 min before expiry

    setTimeout(() => {
        socket.emit('token_refresh_required');
        // Disconnect if no refresh within grace period
        setTimeout(() => socket.disconnect(), 60000);
    }, refreshTime);
}
```

